        #[arg(long)]
        json: bool,
        #[arg(long)]
        safe: bool,
        #[arg(long, value_enum)]
        permission_mode: Option<CliPermissionMode>,
        #[arg(long, hide = true)]
        session_id: Option<String>,
    },
    #[command(hide = true)]
    Serve {
        #[arg(long)]
        prompt: Option<String>,
        #[arg(long, value_enum, default_value_t = StreamMode::Ndjson)]
        stream: StreamMode,
        #[arg(long)]
        model: Option<String>,
        #[arg(long)]
        safe: bool,
        // Serve (IPC-driven) defaults to accept-edits for non-interactive service sessions
        #[arg(long, value_enum, default_value_t = CliPermissionMode::AcceptEdits)]
        permission_mode: CliPermissionMode,
        #[arg(long, hide = true)]
        session_id: Option<String>,
    },
    Spawn {
        #[arg(long)]
        prompt: String,
        #[arg(long)]
        model: Option<String>,
        #[arg(long)]
        safe: bool,
        #[arg(long)]
        json: bool,
        #[arg(long, value_enum)]
        permission_mode: Option<CliPermissionMode>,
    },
    Sessions {
        #[arg(long)]
        json: bool,
        /// Filter sessions by status (running, completed, cancelled, failed)
        #[arg(long, value_enum)]
        status: Option<SessionStatusFilter>,
        /// Filter sessions updated in the last N hours
        #[arg(long)]
        since_hours: Option<u32>,
        /// Search sessions by content/pattern
        #[arg(long)]
        search: Option<String>,
        /// Limit number of sessions shown
        #[arg(long, default_value = "20")]
        limit: usize,
    },
    Resume {
        session_id: String,
        #[arg(long)]
        prompt: Option<String>,
        #[arg(long)]
        model: Option<String>,
        #[arg(long)]
        safe: bool,
        #[arg(long, value_enum, default_value_t = StreamMode::Human)]
        stream: StreamMode,
        #[arg(long)]
        no_tui: bool,
        #[arg(long, value_enum)]
        permission_mode: Option<CliPermissionMode>,
    },
    Logs {
        session_id: String,
        #[arg(long)]
        follow: bool,
        #[arg(long)]
        json: bool,
    },
    Attach {
        session_id: String,
        #[arg(long)]
        json: bool,
    },
    Status {
        session_id: String,
        #[arg(long)]
        json: bool,
    },
    Cancel {
        session_id: String,
        #[arg(long)]
        json: bool,
    },
    /// Manage skills: list, add, remove, update
    Skills {
        /// Output as JSON (shorthand for `dcode-ai skills list --json`)
        #[arg(long)]
        json: bool,
        #[command(subcommand)]
        command: Option<SkillsCommand>,
    },
    Mcp {
        #[arg(long)]
        json: bool,
    },
    Memory {
        #[command(subcommand)]
        command: MemoryCommand,
        #[arg(long)]
