        /// Shell to generate completions for
        #[arg(value_enum, default_value_t = ClapShell::Bash)]
        shell: ClapShell,
    },
    /// Autonomous research helpers (see `crates/autoresearch`, program `.md` files).
    Autoresearch {
        #[command(subcommand)]
