/// Same selection rule as `dcode-ai --resume` (latest `updated_at`).
#[tokio::test]
async fn resume_targets_session_with_latest_updated_at() {
    let temp = tempdir().expect("tempdir");
    let now = Utc::now();

    write_local_config(temp.path());
    write_session(
        temp.path(),
        "session-older",
        now - Duration::minutes(5),
        "MiniMax-M2.5",
        SessionStatus::Completed,
    );
    write_session(
        temp.path(),
        "session-newer",
        now,
        "MiniMax-M2.5-latest",
        SessionStatus::Completed,
    );

    let store = dcode_ai_runtime::session_store::SessionStore::new(
        temp.path().join(".dcode-ai").join("sessions"),
    );
    let ids = store.list().await.expect("list");
    let mut latest: Option<(String, chrono::DateTime<Utc>)> = None;
    for id in ids {
        let Ok(session) = store.load(&id).await else {
            continue;
        };
        let replace = latest
            .as_ref()
            .map(|(_, t)| session.meta.updated_at > *t)
            .unwrap_or(true);
        if replace {
            latest = Some((session.meta.id, session.meta.updated_at));
        }
    }
    assert_eq!(latest.map(|(id, _)| id).as_deref(), Some("session-newer"));
}

#[test]
fn sessions_json_emits_sorted_machine_snapshots() {
    let temp = tempdir().expect("tempdir");
    let now = Utc::now();

    write_session(
        temp.path(),
        "session-older",
        now - Duration::minutes(5),
        "MiniMax-M2.5",
        SessionStatus::Completed,
    );
    write_session(
        temp.path(),
        "session-newer",
        now,
        "MiniMax-M2.5",
        SessionStatus::Running,
    );

    let output = Command::cargo_bin("dcode-ai")
        .expect("binary")
        .current_dir(temp.path())
        .env("HOME", temp.path())
        .arg("sessions")
        .arg("--json")
        .assert()
        .success()
        .get_output()
        .stdout
        .clone();

    let payload: Value = serde_json::from_slice(&output).expect("json");
    let sessions = payload["sessions"].as_array().expect("sessions array");
    assert_eq!(sessions[0]["id"], "session-newer");
    assert_eq!(sessions[0]["status"], "running");
    assert_eq!(sessions[1]["id"], "session-older");
    assert!(
        payload["unreadable"]
            .as_array()
            .expect("unreadable array")
            .is_empty()
    );
}

